from flask import Flask, request
from prometheus_client import Counter, Gauge, Histogram, generate_latest
import time

app = Flask(__name__)

REQUEST_COUNT = Counter('flask_app_requests_total', 'Total request count', ['method', 'endpoint'])
REQUEST_LATENCY = Histogram('flask_app_request_latency_seconds', 'Request latency', ['endpoint'])
IN_PROGRESS = Gauge('flask_app_in_progress_requests', 'Number of in progress requests')
BUSINESS_METRIC = Counter('flask_app_business_metric', 'A specific business metric example')

@app.route('/metrics')
def metrics():
    return generate_latest()

@app.before_request
def before_request():
    request.start_time = time.time()
    REQUEST_COUNT.labels(method=request.method, endpoint=request.path).inc()
    IN_PROGRESS.inc()

@app.after_request
def after_request(response):
    REQUEST_LATENCY.labels(endpoint=request.path).observe(time.time() - request.start_time)
    IN_PROGRESS.dec()
    return response

@app.route('/business')
def business_logic():
    BUSINESS_METRIC.inc()  # Increment business metric counter
    return "Business logic executed", 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)